1	// This file provides command-line interface functionality for gh-aw.
2	// This file (logs_metrics.go) contains functions for extracting and analyzing
3	// metrics from workflow execution logs.
4	//
5	// Key responsibilities:
6	//   - Extracting token usage, cost, and turn metrics from logs
7	//   - Identifying missing tools requested by AI agents
8	//   - Detecting MCP (Model Context Protocol) server failures
9	//   - Aggregating metrics across multiple log files
10	//   - Processing structured output from agent execution
11	
12	package cli
13	
14	import (
15		"encoding/json"
16		"errors"
17		"fmt"
18		"os"
19		"path/filepath"
20		"strings"
21	
22		"github.com/github/gh-aw/pkg/console"
23		"github.com/github/gh-aw/pkg/constants"
24		"github.com/github/gh-aw/pkg/fileutil"
25		"github.com/github/gh-aw/pkg/logger"
26		"github.com/github/gh-aw/pkg/workflow"
27	)
28	
29	var logsMetricsLog = logger.New("cli:logs_metrics")
30	
31	// Shared utilities are now in workflow package
32	// extractJSONMetrics is available as an alias
33	var extractJSONMetrics = workflow.ExtractJSONMetrics
34	
35	// extractLogMetrics extracts metrics from downloaded log files
36	// workflowPath is optional and can be provided to help detect GitHub Copilot coding agent runs
37	func extractLogMetrics(logDir string, verbose bool, workflowPath ...string) (LogMetrics, error) {
38		logsMetricsLog.Printf("Extracting log metrics from: %s", logDir)
39		var metrics LogMetrics
40		if verbose {
41			fmt.Fprintln(os.Stderr, console.FormatVerboseMessage("Beginning metric extraction in "+logDir))
42		}
43	
44		// First check if this is a GitHub Copilot coding agent run (not Copilot CLI)
45		var detector *CopilotCodingAgentDetector
46		if len(workflowPath) > 0 && workflowPath[0] != "" {
47			detector = NewCopilotCodingAgentDetectorWithPath(logDir, verbose, workflowPath[0])
48		} else {
49			detector = NewCopilotCodingAgentDetector(logDir, verbose)
50		}
51		isGitHubCopilotCodingAgent := detector.IsGitHubCopilotCodingAgent()
52		logsMetricsLog.Printf("GitHub Copilot coding agent detected: %v", isGitHubCopilotCodingAgent)
53	
54		if isGitHubCopilotCodingAgent && verbose {
55			fmt.Fprintln(os.Stderr, console.FormatInfoMessage("Detected GitHub Copilot coding agent run, using specialized parser"))
56		}
57	
58		// First check for aw_info.json to determine the engine
59		var detectedEngine workflow.CodingAgentEngine
60		infoFilePath := filepath.Join(logDir, "aw_info.json")
61		logsMetricsLog.Printf("Checking for aw_info.json at: %s", infoFilePath)
62		if _, err := os.Stat(infoFilePath); err == nil {
63			logsMetricsLog.Print("Found aw_info.json, extracting engine")
64			// aw_info.json exists, try to extract engine information
65			if engine := extractEngineFromAwInfo(infoFilePath, verbose); engine != nil {
66				detectedEngine = engine
67				logsMetricsLog.Printf("Detected engine: %s", engine.GetID())
68				if verbose {
69					fmt.Fprintln(os.Stderr, console.FormatInfoMessage("Detected engine from aw_info.json: "+engine.GetID()))
70				}
71			} else {
72				logsMetricsLog.Print("Failed to extract engine from aw_info.json")
73				if verbose {
74					fmt.Fprintln(os.Stderr, console.FormatWarningMessage("aw_info.json exists but failed to extract engine"))
75				}
76			}
77		} else {
78			logsMetricsLog.Printf("No aw_info.json found at %s: %v", infoFilePath, err)
79			if verbose {
80				fmt.Fprintln(os.Stderr, console.FormatWarningMessage("No aw_info.json found at "+infoFilePath))
81			}
82		}
83	
84		// Check for safe_output.jsonl artifact file
85		awOutputPath := filepath.Join(logDir, "safe_output.jsonl")
86		if _, err := os.Stat(awOutputPath); err == nil {
87			if verbose {
88				// Report that the agentic output file was found
89				fileInfo, statErr := os.Stat(awOutputPath)
90				if statErr == nil {
91					fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("Found agentic output file: safe_output.jsonl (%s)", console.FormatFileSize(fileInfo.Size()))))
92				}
93			}
94		}
95	
96		// Check for aw-*.patch and aw-*.bundle artifact files (branch-named patches/bundles)
97		if dirEntries, err := os.ReadDir(logDir); err == nil {
98			for _, entry := range dirEntries {
99				name := entry.Name()
100				isPatch, _ := filepath.Match("aw-*.patch", name)
101				isBundle, _ := filepath.Match("aw-*.bundle", name)
102				if isPatch || isBundle {
103					if verbose {
104						filePath := filepath.Join(logDir, name)
105						if fileInfo, statErr := os.Stat(filePath); statErr == nil {
106							fileType := "git patch"
107							if isBundle {
108								fileType = "git bundle"
109							}
110							fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("Found %s file: %s (%s)", fileType, name, console.FormatFileSize(fileInfo.Size()))))
111						}
112					}
113				}
114			}
115		}
116	
117		// Check for agent_output.json artifact (some workflows may store this under a nested directory)
118		agentOutputPath, agentOutputFound := findAgentOutputFile(logDir)
119		if agentOutputFound {
120			if verbose {
121				fileInfo, statErr := os.Stat(agentOutputPath)
122				if statErr == nil {
123					fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("Found agent output file: %s (%s)", filepath.Base(agentOutputPath), console.FormatFileSize(fileInfo.Size()))))
124				}
125			}
126			// If the file is not already in the logDir root, copy it for convenience
127			if filepath.Dir(agentOutputPath) != logDir {
128				rootCopy := filepath.Join(logDir, constants.AgentOutputArtifactName)
129				if _, err := os.Stat(rootCopy); errors.Is(err, os.ErrNotExist) {
130					if copyErr := fileutil.CopyFile(agentOutputPath, rootCopy); copyErr == nil && verbose {
131						fmt.Fprintln(os.Stderr, console.FormatInfoMessage("Copied agent_output.json to run root for easy access"))
132					}
133				}
134			}
135		}
136	
137		// Walk through all files in the log directory
138		err := filepath.Walk(logDir, func(path string, info os.FileInfo, err error) error {
139			if err != nil {
140				return err
141			}
142	
143			// Skip directories
144			if info.IsDir() {
145				return nil
146			}
147	
148			// Process log files - exclude output artifacts like aw_output.txt and agent_output.json
149			fileName := strings.ToLower(info.Name())
150			if (strings.HasSuffix(fileName, ".log") ||
151				(strings.HasSuffix(fileName, ".txt") && strings.Contains(fileName, "log"))) &&
152				!strings.Contains(fileName, "aw_output") &&
153				fileName != constants.AgentOutputFilename {
154	
155				fileMetrics, err := parseLogFileWithEngine(path, detectedEngine, isGitHubCopilotCodingAgent, verbose)
156				if err != nil && verbose {
157					fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Failed to parse log file %s: %v", path, err)))
158					return nil // Continue processing other files
159				}
160	
161				// Aggregate metrics
162				metrics.TokenUsage += fileMetrics.TokenUsage
163				metrics.EstimatedCost += fileMetrics.EstimatedCost
164				if fileMetrics.Turns > metrics.Turns {
165					// For turns, take the maximum rather than summing, since turns represent
166					// the total conversation turns for the entire workflow run
167					metrics.Turns = fileMetrics.Turns
168				}
169	
170				// Aggregate tool sequences and tool calls
171				metrics.ToolSequences = append(metrics.ToolSequences, fileMetrics.ToolSequences...)
172				metrics.ToolCalls = append(metrics.ToolCalls, fileMetrics.ToolCalls...)
173			}
174	
175			return nil
176		})
177	
178		// Try to parse gateway.jsonl if it exists
179		gatewayMetrics, gatewayErr := parseGatewayLogs(logDir, verbose)
180		if gatewayErr == nil && gatewayMetrics != nil {
181			if verbose {
182				fmt.Fprintln(os.Stderr, console.FormatSuccessMessage("Successfully parsed gateway.jsonl"))
183			}
184			// We've successfully parsed gateway metrics, but we don't add them to the main metrics
185			// structure since they're tracked separately and displayed in their own table
186			logsMetricsLog.Printf("Parsed gateway.jsonl: %d servers, %d requests",
187				len(gatewayMetrics.Servers), gatewayMetrics.TotalRequests)
188		} else if gatewayErr != nil && !strings.Contains(gatewayErr.Error(), "not found") {
189			// Only log if it's an error other than "not found"
190			logsMetricsLog.Printf("Failed to parse gateway.jsonl: %v", gatewayErr)
191			if verbose {
192				fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Failed to parse gateway.jsonl: %v", gatewayErr)))
193			}
194		}
195	
196		if logsMetricsLog.Enabled() {
197			logsMetricsLog.Printf("Metrics extraction completed: tokens=%d, cost=%.4f, turns=%d",
198				metrics.TokenUsage, metrics.EstimatedCost, metrics.Turns)
199		}
200		return metrics, err
201	}
202	
203	// ExtractLogMetricsFromRun extracts log metrics from a processed run's log directory
204	func ExtractLogMetricsFromRun(processedRun ProcessedRun) workflow.LogMetrics {
205		// Use the LogsPath from the WorkflowRun to get metrics
206		if processedRun.Run.LogsPath == "" {
207			return workflow.LogMetrics{}
208		}
209	
210		// Extract metrics from the log directory
211		metrics, err := extractLogMetrics(processedRun.Run.LogsPath, false)
212		if err != nil {
213			return workflow.LogMetrics{}
214		}
215	
216		return metrics
217	}
