219	// extractMissingToolsFromRun extracts missing tool reports from a workflow run's artifacts
220	func extractMissingToolsFromRun(runDir string, run WorkflowRun, verbose bool) ([]MissingToolReport, error) {
221		logsMetricsLog.Printf("Extracting missing tools from run: %d", run.DatabaseID)
222		var missingTools []MissingToolReport
223	
224		// Look for the safe output artifact file that contains structured JSON with items array
225		// This file is created by the collect_ndjson_output.cjs script during workflow execution
226		// After artifact refactoring, the file is flattened to agent_output.json at root
227		agentOutputJSONPath := filepath.Join(runDir, constants.AgentOutputFilename)
228	
229		// Support both new flattened form (agent_output.json) and old forms for backward compatibility:
230		// 1. New: agent_output.json at root (after flattening)
231		// 2. Old: agent-output directory with nested agent-output file
232		// 3. Fallback: search recursively
233		var resolvedAgentOutputFile string
234		if stat, err := os.Stat(agentOutputJSONPath); err == nil && !stat.IsDir() {
235			// New flattened structure: agent_output.json at root
236			resolvedAgentOutputFile = agentOutputJSONPath
237			if verbose {
238				fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("Found %s at root: %s", constants.AgentOutputFilename, agentOutputJSONPath)))
239			}
240		} else {
241			// Try old structure: agent-output directory
242			agentOutputPath := filepath.Join(runDir, constants.AgentOutputArtifactName)
243			if stat, err := os.Stat(agentOutputPath); err == nil {
244				if stat.IsDir() {
245					// Directory form – look for nested file
246					nested := filepath.Join(agentOutputPath, constants.AgentOutputArtifactName)
247					if _, nestedErr := os.Stat(nested); nestedErr == nil {
248						resolvedAgentOutputFile = nested
249						if verbose {
250							fmt.Fprintln(os.Stderr, console.FormatInfoMessage("agent_output.json is a directory; using nested file "+nested))
251						}
252					} else if verbose {
253						fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("agent_output.json directory present but nested file missing: %v", nestedErr)))
254					}
255				} else {
256					// Regular file
257					resolvedAgentOutputFile = agentOutputPath
258				}
259			} else {
260				// Not present at root – search recursively (depth-first) for a file named agent_output.json
261				if found, ok := findAgentOutputFile(runDir); ok {
262					resolvedAgentOutputFile = found
263					if verbose && found != agentOutputPath {
264						fmt.Fprintln(os.Stderr, console.FormatInfoMessage("Found agent_output.json at "+found))
265					}
266				}
267			}
268		}
269	
270		if resolvedAgentOutputFile != "" {
271			// Sanitize the path to prevent path traversal attacks
272			cleanPath := filepath.Clean(resolvedAgentOutputFile)
273	
274			// Read the safe output artifact file
275			content, readErr := os.ReadFile(cleanPath)
276			if readErr != nil {
277				if verbose {
278					fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Failed to read safe output file %s: %v", cleanPath, readErr)))
279				}
280				return missingTools, nil // Continue processing without this file
281			}
282	
283			// Parse the structured JSON output from the collect script
284			var safeOutput struct {
285				Items  []json.RawMessage `json:"items"`
286				Errors []string          `json:"errors,omitempty"`
287			}
288	
289			if err := json.Unmarshal(content, &safeOutput); err != nil {
290				if verbose {
291					fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Failed to parse safe output JSON from %s: %v", cleanPath, err)))
292				}
293				return missingTools, nil // Continue processing without this file
294			}
295	
296			// Extract missing-tool entries from the items array
297			for _, itemRaw := range safeOutput.Items {
298				var item struct {
299					Type         string `json:"type"`
300					Tool         string `json:"tool,omitempty"`
301					Reason       string `json:"reason,omitempty"`
302					Alternatives string `json:"alternatives,omitempty"`
303					Timestamp    string `json:"timestamp,omitempty"`
304				}
305	
306				if err := json.Unmarshal(itemRaw, &item); err != nil {
307					if verbose {
308						fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Failed to parse item from safe output: %v", err)))
309					}
310					continue // Skip malformed items
311				}
312	
313				// Check if this is a missing-tool entry
314				if item.Type == "missing_tool" {
315					missingTool := MissingToolReport{
316						Tool:         item.Tool,
317						Reason:       item.Reason,
318						Alternatives: item.Alternatives,
319						Timestamp:    item.Timestamp,
320						WorkflowName: run.WorkflowName,
321						RunID:        run.DatabaseID,
322					}
323					missingTools = append(missingTools, missingTool)
324	
325					if verbose {
326						fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("Found missing_tool entry: %s (%s)", item.Tool, item.Reason)))
327					}
328				}
329			}
330	
331			if verbose && len(missingTools) > 0 {
332				fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("Found %d missing tool reports in safe output artifact for run %d", len(missingTools), run.DatabaseID)))
333			}
334			logsMetricsLog.Printf("Found %d missing tool reports", len(missingTools))
335		} else {
336			logsMetricsLog.Print("No safe output artifact found")
337			if verbose {
338				fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("No safe output artifact found at %s for run %d", agentOutputJSONPath, run.DatabaseID)))
339			}
340		}
341	
342		return missingTools, nil
343	}
