345	// extractNoopsFromRun extracts noop messages from a workflow run's artifacts
346	func extractNoopsFromRun(runDir string, run WorkflowRun, verbose bool) ([]NoopReport, error) {
347		logsMetricsLog.Printf("Extracting noops from run: %d", run.DatabaseID)
348		var noops []NoopReport
349	
350		// Look for the safe output artifact file that contains structured JSON with items array
351		// This file is created by the collect_ndjson_output.cjs script during workflow execution
352		// After artifact refactoring, the file is flattened to agent_output.json at root
353		agentOutputJSONPath := filepath.Join(runDir, constants.AgentOutputFilename)
354	
355		// Support both new flattened form (agent_output.json) and old forms for backward compatibility:
356		// 1. New: agent_output.json at root (after flattening)
357		// 2. Old: agent-output directory with nested agent-output file
358		// 3. Fallback: search recursively
359		var resolvedAgentOutputFile string
360		if stat, err := os.Stat(agentOutputJSONPath); err == nil && !stat.IsDir() {
361			// New flattened structure: agent_output.json at root
362			resolvedAgentOutputFile = agentOutputJSONPath
363			if verbose {
364				fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("Found %s at root: %s", constants.AgentOutputFilename, agentOutputJSONPath)))
365			}
366		} else {
367			// Try old structure: agent-output directory
368			agentOutputPath := filepath.Join(runDir, constants.AgentOutputArtifactName)
369			if stat, err := os.Stat(agentOutputPath); err == nil {
370				if stat.IsDir() {
371					// Directory form – look for nested file
372					nested := filepath.Join(agentOutputPath, constants.AgentOutputArtifactName)
373					if _, nestedErr := os.Stat(nested); nestedErr == nil {
374						resolvedAgentOutputFile = nested
375						if verbose {
376							fmt.Fprintln(os.Stderr, console.FormatInfoMessage("agent_output.json is a directory; using nested file "+nested))
377						}
378					} else if verbose {
379						fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("agent_output.json directory present but nested file missing: %v", nestedErr)))
380					}
381				} else {
382					// Regular file
383					resolvedAgentOutputFile = agentOutputPath
384				}
385			} else {
386				// Not present at root – search recursively (depth-first) for a file named agent_output.json
387				if found, ok := findAgentOutputFile(runDir); ok {
388					resolvedAgentOutputFile = found
389					if verbose && found != agentOutputPath {
390						fmt.Fprintln(os.Stderr, console.FormatInfoMessage("Found agent_output.json at "+found))
391					}
392				}
393			}
394		}
395	
396		if resolvedAgentOutputFile != "" {
397			// Sanitize the path to prevent path traversal attacks
398			cleanPath := filepath.Clean(resolvedAgentOutputFile)
399	
400			// Read the safe output artifact file
401			content, readErr := os.ReadFile(cleanPath)
402			if readErr != nil {
403				if verbose {
404					fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Failed to read safe output file %s: %v", cleanPath, readErr)))
405				}
406				return noops, nil // Continue processing without this file
407			}
408	
409			// Parse the structured JSON output from the collect script
410			var safeOutput struct {
411				Items  []json.RawMessage `json:"items"`
412				Errors []string          `json:"errors,omitempty"`
413			}
414	
415			if err := json.Unmarshal(content, &safeOutput); err != nil {
416				if verbose {
417					fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Failed to parse safe output JSON from %s: %v", cleanPath, err)))
418				}
419				return noops, nil // Continue processing without this file
420			}
421	
422			// Extract noop entries from the items array
423			for _, itemRaw := range safeOutput.Items {
424				var item struct {
425					Type      string `json:"type"`
426					Message   string `json:"message,omitempty"`
427					Timestamp string `json:"timestamp,omitempty"`
428				}
429	
430				if err := json.Unmarshal(itemRaw, &item); err != nil {
431					if verbose {
432						fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Failed to parse item from safe output: %v", err)))
433					}
434					continue // Skip malformed items
435				}
436	
437				// Check if this is a noop entry
438				if item.Type == "noop" {
439					noop := NoopReport{
440						Message:      item.Message,
441						Timestamp:    item.Timestamp,
442						WorkflowName: run.WorkflowName,
443						RunID:        run.DatabaseID,
444					}
445					noops = append(noops, noop)
446	
447					if verbose {
448						fmt.Fprintln(os.Stderr, console.FormatInfoMessage("Found noop entry: "+item.Message))
449					}
450				}
451			}
452	
453			if verbose && len(noops) > 0 {
454				fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("Found %d noop messages in safe output artifact for run %d", len(noops), run.DatabaseID)))
455			}
456			logsMetricsLog.Printf("Found %d noop messages", len(noops))
457		} else {
458			logsMetricsLog.Print("No safe output artifact found")
459			if verbose {
460				fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("No safe output artifact found at %s for run %d", agentOutputJSONPath, run.DatabaseID)))
461			}
462		}
463	
464		return noops, nil
465	}
