467	// extractMissingDataFromRun extracts missing data reports from a workflow run's artifacts
468	func extractMissingDataFromRun(runDir string, run WorkflowRun, verbose bool) ([]MissingDataReport, error) {
469		logsMetricsLog.Printf("Extracting missing data from run: %d", run.DatabaseID)
470		var missingData []MissingDataReport
471	
472		// Look for the safe output artifact file that contains structured JSON with items array
473		// This file is created by the collect_ndjson_output.cjs script during workflow execution
474		// After artifact refactoring, the file is flattened to agent_output.json at root
475		agentOutputJSONPath := filepath.Join(runDir, constants.AgentOutputFilename)
476	
477		// Support both new flattened form (agent_output.json) and old forms for backward compatibility:
478		// 1. New: agent_output.json at root (after flattening)
479		// 2. Old: agent-output directory with nested agent-output file
480		// 3. Fallback: search recursively
481		var resolvedAgentOutputFile string
482		if stat, err := os.Stat(agentOutputJSONPath); err == nil && !stat.IsDir() {
483			// New flattened structure: agent_output.json at root
484			resolvedAgentOutputFile = agentOutputJSONPath
485			if verbose {
486				fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("Found %s at root: %s", constants.AgentOutputFilename, agentOutputJSONPath)))
487			}
488		} else {
489			// Try old structure: agent-output directory
490			agentOutputPath := filepath.Join(runDir, constants.AgentOutputArtifactName)
491			if stat, err := os.Stat(agentOutputPath); err == nil {
492				if stat.IsDir() {
493					// Directory form – look for nested file
494					nested := filepath.Join(agentOutputPath, constants.AgentOutputArtifactName)
495					if _, nestedErr := os.Stat(nested); nestedErr == nil {
496						resolvedAgentOutputFile = nested
497						if verbose {
498							fmt.Fprintln(os.Stderr, console.FormatInfoMessage("agent_output.json is a directory; using nested file "+nested))
499						}
500					} else if verbose {
501						fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("agent_output.json directory present but nested file missing: %v", nestedErr)))
502					}
503				} else {
504					// Regular file
505					resolvedAgentOutputFile = agentOutputPath
506				}
507			} else {
508				// Not present at root – search recursively (depth-first) for a file named agent_output.json
509				if found, ok := findAgentOutputFile(runDir); ok {
510					resolvedAgentOutputFile = found
511					if verbose && found != agentOutputPath {
512						fmt.Fprintln(os.Stderr, console.FormatInfoMessage("Found agent_output.json at "+found))
513					}
514				}
515			}
516		}
517	
518		if resolvedAgentOutputFile != "" {
519			// Sanitize the path to prevent path traversal attacks
520			cleanPath := filepath.Clean(resolvedAgentOutputFile)
521	
522			// Read the safe output artifact file
523			content, readErr := os.ReadFile(cleanPath)
524			if readErr != nil {
525				if verbose {
526					fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Failed to read safe output file %s: %v", cleanPath, readErr)))
527				}
528				return missingData, nil // Continue processing without this file
529			}
530	
531			// Parse the structured JSON output from the collect script
532			var safeOutput struct {
533				Items  []json.RawMessage `json:"items"`
534				Errors []string          `json:"errors,omitempty"`
535			}
536	
537			if err := json.Unmarshal(content, &safeOutput); err != nil {
538				if verbose {
539					fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Failed to parse safe output JSON from %s: %v", cleanPath, err)))
540				}
541				return missingData, nil // Continue processing without this file
542			}
543	
544			// Extract missing_data entries from the items array
545			for _, itemRaw := range safeOutput.Items {
546				var item struct {
547					Type         string `json:"type"`
548					DataType     string `json:"data_type,omitempty"`
549					Reason       string `json:"reason,omitempty"`
550					Context      string `json:"context,omitempty"`
551					Alternatives string `json:"alternatives,omitempty"`
552					Timestamp    string `json:"timestamp,omitempty"`
553				}
554	
555				if err := json.Unmarshal(itemRaw, &item); err != nil {
556					if verbose {
557						fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Failed to parse item from safe output: %v", err)))
558					}
559					continue // Skip malformed items
560				}
561	
562				// Check if this is a missing_data entry
563				if item.Type == "missing_data" {
564					missingDataItem := MissingDataReport{
565						DataType:     item.DataType,
566						Reason:       item.Reason,
567						Context:      item.Context,
568						Alternatives: item.Alternatives,
569						Timestamp:    item.Timestamp,
570						WorkflowName: run.WorkflowName,
571						RunID:        run.DatabaseID,
572					}
573					missingData = append(missingData, missingDataItem)
574	
575					if verbose {
576						fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("Found missing_data entry: %s (%s)", item.DataType, item.Reason)))
577					}
578				}
579			}
580	
581			if verbose && len(missingData) > 0 {
582				fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("Found %d missing data reports in safe output artifact for run %d", len(missingData), run.DatabaseID)))
583			}
584			logsMetricsLog.Printf("Found %d missing data reports", len(missingData))
585		} else {
586			logsMetricsLog.Print("No safe output artifact found")
587			if verbose {
588				fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("No safe output artifact found at %s for run %d", agentOutputJSONPath, run.DatabaseID)))
589			}
590		}
591	
592		return missingData, nil
593	}
594	
595	// extractMCPFailuresFromRun extracts MCP server failure reports from a workflow run's logs
596	func extractMCPFailuresFromRun(runDir string, run WorkflowRun, verbose bool) ([]MCPFailureReport, error) {
597		logsMetricsLog.Printf("Extracting MCP failures from run: %d", run.DatabaseID)
598		var mcpFailures []MCPFailureReport
599	
600		// Look for agent output logs that contain the system init entry with MCP server status
601		// This information is available in the raw log files, typically with names containing "log"
602		err := filepath.Walk(runDir, func(path string, info os.FileInfo, err error) error {
603			if err != nil {
604				return err
605			}
606	
607			// Skip directories
608			if info.IsDir() {
609				return nil
610			}
611	
612			// Process log files - exclude output artifacts
613			fileName := strings.ToLower(info.Name())
614			if (strings.HasSuffix(fileName, ".log") ||
615				(strings.HasSuffix(fileName, ".txt") && strings.Contains(fileName, "log"))) &&
616				!strings.Contains(fileName, "aw_output") &&
617				!strings.Contains(fileName, "agent_output") &&
618				!strings.Contains(fileName, "access") {
619	
620				failures, parseErr := extractMCPFailuresFromLogFile(path, run, verbose)
621				if parseErr != nil {
622					if verbose {
623						fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Failed to parse MCP failures from %s: %v", filepath.Base(path), parseErr)))
624					}
625					return nil // Continue processing other files
626				}
627				mcpFailures = append(mcpFailures, failures...)
628			}
629	
630			return nil
631		})
632	
633		if err != nil {
634			return mcpFailures, fmt.Errorf("error walking run directory: %w", err)
635		}
636	
637		if verbose && len(mcpFailures) > 0 {
638			fmt.Fprintln(os.Stderr, console.FormatInfoMessage(fmt.Sprintf("Found %d MCP server failures for run %d", len(mcpFailures), run.DatabaseID)))
639		}
640		logsMetricsLog.Printf("Found %d MCP failures", len(mcpFailures))
641	
642		return mcpFailures, nil
643	}
644	
645	// extractMCPFailuresFromLogFile parses a single log file for MCP server failures
646	func extractMCPFailuresFromLogFile(logPath string, run WorkflowRun, verbose bool) ([]MCPFailureReport, error) {
647		var mcpFailures []MCPFailureReport
648	
649		content, err := os.ReadFile(logPath)
650		if err != nil {
651			return mcpFailures, fmt.Errorf("error reading log file: %w", err)
652		}
653	
654		logContent := string(content)
655	
656		// First try to parse as JSON array
657		var logEntries []map[string]any
658		if err := json.Unmarshal(content, &logEntries); err == nil {
659			// Successfully parsed as JSON array, process entries
660			for _, entry := range logEntries {
661				if entryType, ok := entry["type"].(string); ok && entryType == "system" {
662					if subtype, ok := entry["subtype"].(string); ok && subtype == "init" {
663						if mcpServers, ok := entry["mcp_servers"].([]any); ok {
664							for _, serverInterface := range mcpServers {
665								if server, ok := serverInterface.(map[string]any); ok {
666									serverName, hasName := server["name"].(string)
667									status, hasStatus := server["status"].(string)
668	
669									if hasName && hasStatus && status == "failed" {
670										failure := MCPFailureReport{
671											ServerName:   serverName,
672											Status:       status,
673											WorkflowName: run.WorkflowName,
674											RunID:        run.DatabaseID,
675										}
676	
677										// Try to extract timestamp if available
678										if timestamp, hasTimestamp := entry["timestamp"].(string); hasTimestamp {
679											failure.Timestamp = timestamp
680										}
681	
682										mcpFailures = append(mcpFailures, failure)
683	
684										if verbose {
685											fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Found MCP server failure: %s (status: %s)", serverName, status)))
686										}
687									}
688								}
689							}
690						}
691					}
692				}
693			}
694		} else {
695			// Fallback: Try to parse as JSON lines (Claude logs are typically NDJSON format)
696			lines := strings.SplitSeq(logContent, "\n")
697			for line := range lines {
698				line = strings.TrimSpace(line)
699				if line == "" || !strings.HasPrefix(line, "{") {
700					continue
701				}
702	
703				// Try to parse each line as JSON
704				var entry map[string]any
705				if err := json.Unmarshal([]byte(line), &entry); err != nil {
706					continue // Skip non-JSON lines
707				}
708	
709				// Look for system init entries that contain MCP server information
710				if entryType, ok := entry["type"].(string); ok && entryType == "system" {
711					if subtype, ok := entry["subtype"].(string); ok && subtype == "init" {
712						if mcpServers, ok := entry["mcp_servers"].([]any); ok {
713							for _, serverInterface := range mcpServers {
714								if server, ok := serverInterface.(map[string]any); ok {
715									serverName, hasName := server["name"].(string)
716									status, hasStatus := server["status"].(string)
717	
718									if hasName && hasStatus && status == "failed" {
719										failure := MCPFailureReport{
720											ServerName:   serverName,
721											Status:       status,
722											WorkflowName: run.WorkflowName,
723											RunID:        run.DatabaseID,
724										}
725	
726										// Try to extract timestamp if available
727										if timestamp, hasTimestamp := entry["timestamp"].(string); hasTimestamp {
728											failure.Timestamp = timestamp
729										}
730	
731										mcpFailures = append(mcpFailures, failure)
732	
733										if verbose {
734											fmt.Fprintln(os.Stderr, console.FormatWarningMessage(fmt.Sprintf("Found MCP server failure: %s (status: %s)", serverName, status)))
735										}
736									}
737								}
738							}
739						}
740					}
741				}
742			}
743		}
744	
745		return mcpFailures, nil
746	}
