// words like "calls", "to", "for", "on", "or", "with", "since", "launches",
// "misuse", "unified" as tool call names from agent STDIO logs.
func TestExtractToolNameDoesNotMatchEnglishWords(t *testing.T) {
	// English stop words that should NOT be extracted as tool names
	badMatches := []string{
		"calls",
		"call",
		"to",
		"for",
		"on",
		"or",
		"with",
		"since",
		"launches",
		"misuse",
		"unified",
	}

	for _, word := range badMatches {
		t.Run("word_"+word, func(t *testing.T) {
			// Test the raw extractToolName function
			result := extractToolName("the agent " + word + " a command")
			if result != "" {
				t.Errorf("extractToolName should NOT extract '%s' from prose 'the agent %s a command', got '%s'",
					word, word, result)
			}
		})
	}
}

// TestParseCopilotCodingAgentLogMetricsNoisyLog verifies that the full parsing
// function does not extract tools from natural language prose in agent logs.
func TestParseCopilotCodingAgentLogMetricsNoisyLog(t *testing.T) {
	// Simulates a realistic agent log that contains natural language prose
	// mixed with actual tool invocations
	logContent := `
the agent calls a command to process the request
the agent calls another tool for verification
calling the function on the remote server
executing with since the last update
using tool: misusage of the api
unified launch for the project
the agent calls since it needs to
calls to the server
for on with
or since launches
misuse unified calls

Task iteration 1: Starting
Executing tool: github_search
Task iteration 2: Processing
Tool call: write_file
Task iteration 3: Finishing
Calling: read_file
`

	metrics := ParseCopilotCodingAgentLogMetrics(logContent, false)

	// Collect all tool names
	toolNames := make(map[string]bool)
	for _, tc := range metrics.ToolCalls {
		toolNames[strings.ToLower(tc.Name)] = true
	}

	// These are the ONLY tool names we should see
	expectedTools := map[string]bool{
		"github_search": true,
		"write_file":    true,
		"read_file":     true,
	}

	// Check that no English words appear as tool names
	englishWordToolNames := []string{"calls", "call", "to", "for", "on", "or", "with", "since", "launches", "misuse", "unified"}
	for _, word := range englishWordToolNames {
		if toolNames[word] {
			t.Errorf("English word '%s' should NOT appear as a tool name in ToolCalls", word)
		}
	}

	// Check that expected tools are present
	for expectedTool := range expectedTools {
		if !toolNames[expectedTool] {
			t.Errorf("Expected tool '%s' was not found in ToolCalls", expectedTool)
		}
	}

	// Check total count
	if len(metrics.ToolCalls) != len(expectedTools) {
		t.Errorf("Expected %d tool types, got %d. Tool names: %v",
			len(expectedTools), len(metrics.ToolCalls), toolNames)
	}
}

