// the GPL Dependency Cleaner scenario from the bug report.
func TestParseCopilotCodingAgentLogMetricsToolBreadth(t *testing.T) {
	// Simulates a log similar to the gpclean run that triggered the bug
	// Contains many instances of prose mentioning "calls" and other English words
	logContent := `
the agent calls a command every time
the agent calls another tool
the agent calls to process data
the agent calls for verification
the agent calls on success
the agent calls with caution
the agent calls since the update
the agent calls or reports
the agent launches the process
the agent uses unified approach
misuse of the api
calling the function to process
executing with the unified framework
using tool for the task
since the agent calls many times

Task iteration 1
Executing tool: startHttpServer
Task iteration 2
Tool call: noop
Task iteration 3
Calling: label_agent
`

	metrics := ParseCopilotCodingAgentLogMetrics(logContent, false)

	// Check tool breadth - should only have 3 real tools
	expectedToolCount := 3
	if len(metrics.ToolCalls) != expectedToolCount {
		toolNames := make([]string, len(metrics.ToolCalls))
		for i, tc := range metrics.ToolCalls {
			toolNames[i] = tc.Name
		}
		t.Errorf("Expected %d tool types (startHttpServer, noop, label_agent), got %d: %v",
			expectedToolCount, len(metrics.ToolCalls), toolNames)
	}

	// Verify that English words are NOT present
	for _, tc := range metrics.ToolCalls {
		name := strings.ToLower(tc.Name)
		switch name {
		case "starthttpserver", "noop", "label_agent":
			// Expected
		default:
			t.Errorf("Unexpected tool name: '%s'", tc.Name)
		}
	}
}

