func TestExtractToolNameRealToolNames(t *testing.T) {
	tests := []struct {
		name     string
		line     string
		expected string
	}{
		{
			name:     "tool: github_search",
			line:     "Using tool: github_search",
			expected: "github_search",
		},
		{
			name:     "calling: write_file",
			line:     "Calling: write_file",
			expected: "write_file",
		},
		{
			name:     "executing: bash",
			line:     "Executing: bash",
			expected: "bash",
		},
		{
			name:     "using tool: read",
			line:     "Using tool: read",
			expected: "read",
		},
		{
			name:     "Executing tool: pattern",
			line:     "Executing tool: github_search",
			expected: "github_search",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
