package cli

import (
	"strings"
	"testing"

	"github.com/github/gh-aw/pkg/workflow"
)

// TestExtractToolNameDoesNotMatchEnglishWords verifies that common English words
// appearing in natural language prose are NOT extracted as tool names.
// This is a regression test for the bug where the tool usage parser extracts
// words like "calls", "to", "for", "on", "or", "with", "since", "launches",
// "misuse", "unified" as tool call names from agent STDIO logs.
func TestExtractToolNameDoesNotMatchEnglishWords(t *testing.T) {
	// English stop words that should NOT be extracted as tool names
	badMatches := []string{
		"calls",
		"call",
		"to",
		"for",
		"on",
		"or",
		"with",
		"since",
		"launches",
		"misuse",
		"unified",
	}

	for _, word := range badMatches {
		t.Run("word_"+word, func(t *testing.T) {
			// Test the raw extractToolName function
			result := extractToolName("the agent " + word + " a command")
			if result != "" {
				t.Errorf("extractToolName should NOT extract '%s' from prose 'the agent %s a command', got '%s'",
					word, word, result)
			}
		})
	}
}

// TestParseCopilotCodingAgentLogMetricsNoisyLog verifies that the full parsing
// function does not extract tools from natural language prose in agent logs.
func TestParseCopilotCodingAgentLogMetricsNoisyLog(t *testing.T) {
	// Simulates a realistic agent log that contains natural language prose
	// mixed with actual tool invocations
	logContent := `
the agent calls a command to process the request
the agent calls another tool for verification
calling the function on the remote server
executing with since the last update
using tool: misusage of the api
unified launch for the project
the agent calls since it needs to
calls to the server
for on with
or since launches
misuse unified calls

Task iteration 1: Starting
Executing tool: github_search
Task iteration 2: Processing
Tool call: write_file
Task iteration 3: Finishing
Calling: read_file
`

	metrics := ParseCopilotCodingAgentLogMetrics(logContent, false)

	// Collect all tool names
	toolNames := make(map[string]bool)
	for _, tc := range metrics.ToolCalls {
		toolNames[strings.ToLower(tc.Name)] = true
	}

	// These are the ONLY tool names we should see
	expectedTools := map[string]bool{
		"github_search": true,
		"write_file":    true,
		"read_file":     true,
	}

	// Check that no English words appear as tool names
	englishWordToolNames := []string{"calls", "call", "to", "for", "on", "or", "with", "since", "launches", "misuse", "unified"}
	for _, word := range englishWordToolNames {
		if toolNames[word] {
			t.Errorf("English word '%s' should NOT appear as a tool name in ToolCalls", word)
		}
	}

	// Check that expected tools are present
	for expectedTool := range expectedTools {
		if !toolNames[expectedTool] {
			t.Errorf("Expected tool '%s' was not found in ToolCalls", expectedTool)
		}
	}

	// Check total count
	if len(metrics.ToolCalls) != len(expectedTools) {
		t.Errorf("Expected %d tool types, got %d. Tool names: %v",
			len(expectedTools), len(metrics.ToolCalls), toolNames)
	}
}

// TestParseCopilotCodingAgentLogMetricsToolBreadth is a broader test simulating
// the GPL Dependency Cleaner scenario from the bug report.
func TestParseCopilotCodingAgentLogMetricsToolBreadth(t *testing.T) {
	// Simulates a log similar to the gpclean run that triggered the bug
	// Contains many instances of prose mentioning "calls" and other English words
	logContent := `
the agent calls a command every time
the agent calls another tool
the agent calls to process data
the agent calls for verification
the agent calls on success
the agent calls with caution
the agent calls since the update
the agent calls or reports
the agent launches the process
the agent uses unified approach
misuse of the api
calling the function to process
executing with the unified framework
using tool for the task
since the agent calls many times

Task iteration 1
Executing tool: startHttpServer
Task iteration 2
Tool call: noop
Task iteration 3
Calling: label_agent
`

	metrics := ParseCopilotCodingAgentLogMetrics(logContent, false)

	// Check tool breadth - should only have 3 real tools
	expectedToolCount := 3
	if len(metrics.ToolCalls) != expectedToolCount {
		toolNames := make([]string, len(metrics.ToolCalls))
		for i, tc := range metrics.ToolCalls {
			toolNames[i] = tc.Name
		}
		t.Errorf("Expected %d tool types (startHttpServer, noop, label_agent), got %d: %v",
			expectedToolCount, len(metrics.ToolCalls), toolNames)
	}

	// Verify that English words are NOT present
	for _, tc := range metrics.ToolCalls {
		name := strings.ToLower(tc.Name)
		switch name {
		case "starthttpserver", "noop", "label_agent":
			// Expected
		default:
			t.Errorf("Unexpected tool name: '%s'", tc.Name)
		}
	}
}

// TestExtractToolNameRealToolNames verifies that real tool names ARE still extracted
func TestExtractToolNameRealToolNames(t *testing.T) {
	tests := []struct {
		name     string
		line     string
		expected string
	}{
		{
			name:     "tool: github_search",
			line:     "Using tool: github_search",
			expected: "github_search",
		},
		{
			name:     "calling: write_file",
			line:     "Calling: write_file",
			expected: "write_file",
		},
		{
			name:     "executing: bash",
			line:     "Executing: bash",
			expected: "bash",
		},
		{
			name:     "using tool: read",
			line:     "Using tool: read",
			expected: "read",
		},
		{
			name:     "Executing tool: pattern",
			line:     "Executing tool: github_search",
			expected: "github_search",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result := extractToolName(tt.line)
			if result != tt.expected {
				t.Errorf("Expected '%s', got '%s'", tt.expected, result)
			}
		})
	}
}

// TestToolCallInfoMaxInputSize confirms that real tool calls with payloads
// have non-zero MaxInputSize
func TestToolCallInfoMaxInputSize(t *testing.T) {
	logContent := `
